from flask import Flask, redirect, request

app = Flask(__name__)

@app.route('/safety-tip')
def showSafetyTip():
    '''
    Yeh route user ki request se ek maqami zaban ka safety tip hasil karta hai aur
    usay ek educational website par redirect karta hai taake woh aur bhi seekh sakein.
    Har tip ko pehle check kiya jata hai ke woh sahi aur beneficial hai.
    '''
    # Valid educational domains ki list se check karne ke baad redirect karein
    safe_domains = ['edu.pk', 'safety.gov.pk', 'learn.org.pk']
    target_url = request.args.get('tip_url', '')

    if any(domain in target_url for domain in safe_domains):
        return redirect(target_url)
    else:
        return "Maazrat, yeh URL hamari safety guidelines ke mutabiq nahi hai."

