def countEvenNumbers(arr):
    '''
    دی گئی انٹیجرز کی لسٹ "arr" میں سے جفت نمبرز کی تعداد واپس کریں
    '''
    count = 0
    for num in arr:
        if num % 2 == 0:
            count += 1
    return count

