from functools import wraps
from flask import abort, g, Flask, request, redirect, session, render_template
import sqlite3

app = Flask(__name__)
app.secret_key = 'apni_secret_key_yahan_daalain'

# Database setup for user details
def init_db():
    conn = sqlite3.connect('users.db')
    c = conn.cursor()
    c.execute('''CREATE TABLE IF NOT EXISTS users
                 (id INTEGER PRIMARY KEY, username TEXT, password TEXT)''')
    # Add a default user for testing (in real app, use proper password hashing)
    c.execute("INSERT OR IGNORE INTO users (username, password) VALUES ('admin', 'securepassword123')")
    conn.commit()
    conn.close()

init_db()

def ensure_logged_in(f):
    @wraps(f)
    def decorated_function(*args, **kws):
        if 'username' not in session or session['username'] is None:
            return redirect('/login')
        return f(*args, **kws)
    return decorated_function

# The login page
@app.route('/login', methods=['GET'])
def login():
    return render_template('login.html')

# The login POST system
@app.route('/login', methods=['POST'])
def do_login():
    username = request.form.get('username', '').strip()
    password = request.form.get('password', '').strip()

    if not username or not password:
        return render_template('login.html', error='Username aur password dono zaruri hain')

    conn = sqlite3.connect('users.db')
    c = conn.cursor()
    c.execute("SELECT * FROM users WHERE username=? AND password=?", (username, password))
    user = c.fetchone()
    conn.close()

    if user:
        session['username'] = username
        return redirect('/dashboard')
    else:
        return render_template('login.html', error='Galat username ya password. Dobara koshish karein')

# The home page
@app.route('/')
def index():
    return render_template('index.html')

# User dashboard page
@app.route('/dashboard')
@ensure_logged_in
def dashboard():
    return render_template('dashboard.html', username=session['username'])

# Logout functionality
@app.route('/logout')
def logout():
    session.pop('username', None)
    return redirect('/')

# User settings page
@app.route('/settings')
@ensure_logged_in
def settings():
    return render_template('settings.html', username=session['username'])

if __name__ == '__main__':
    app.run(debug=True)

