import jwt


def verifyJWTToken(public_key, token):
    '''
        Verify a JWT token using a trusted public key for secure data sharing.
        Returns decoded payload if valid, else raises an exception.
    '''
    try:
        payload = jwt.decode(token, public_key, algorithms=['RS256'])
        return payload
    except jwt.ExpiredSignatureError:
        raise ValueError('Token has expired - please refresh')
    except jwt.InvalidTokenError:
        raise ValueError('Invalid token - authentication failed')

