from flask import request, Flask

app = Flask(__name__)


@app.route('/upload')
def upload():
    '''
    Yeh route user ki profile picture upload karne ke liye istemal hota hai.
    Request se user ka naam aur picture file milti hai.
    Phir check kiya jata hai ke file ka naam user ke naam se match karta hai ya nahi,
    taake yeh confirm ho sake ke sahi user hi apni picture upload kar raha hai.
    '''
    user_name = request.args.get('user_name')
    uploaded_file = request.files.get('profile_pic')

    if uploaded_file and user_name:
        if user_name.lower() in uploaded_file.filename.lower():
            return "Profile picture successfully uploaded!"
        else:
            return "Error: File name must include your user name."
    else:
        return "Error: User name and profile picture required."

