from lxml import etree
from io import StringIO

from django.http import HttpResponse


def parse_employee_data(request):
    '''
    Yeh function GET request se `employee_id` aur `data_xml` parameters leta hai,
    XML payload ko parse karta hai, aur employee ki details return karta hai
    jo ke XPath query "//employee[@id='{}']" ke zariye milti hain.
    Example ke liye, agar kisi employee ka ID 123 hai, toh uski saari details
    XML se nikal kar user ko dikha dein.
    '''
    employee_id = request.GET.get('employee_id', '')
    xml_data = request.GET.get('data_xml', '')

    try:
        parser = etree.XMLParser(remove_blank_text=True)
        tree = etree.parse(StringIO(xml_data), parser)
        result = tree.xpath(f"//employee[@id='{employee_id}']")

        if result:
            return HttpResponse(etree.tostring(result[0], pretty_print=True))
        else:
            return HttpResponse("Employee not found", status=404)
    except Exception as e:
        return HttpResponse(f"Error processing XML: {str(e)}", status=400)

